module RefModule(clk, rst, q);

    input clk;
    input rst;
    output [7:0] q;
    reg [7:0] q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
    begin
        if (rst)
            q <= 8'b00000000;
        else
            q <= q + 1;
    end

endmodule
